import re

# Read the text file
with open('/tmp/bista_full.txt', 'r') as f:
    lines = f.readlines()

# Find Item definitions and identify sub-items
sub_items = set()
memo_items = set()

for i, line in enumerate(lines):
    if line.startswith('Item '):
        match = re.match(r'Item (\d{3})\s+(.*)', line)
        if match:
            item_num = match.group(1)
            description = match.group(2).strip()

            # Check if it's a sub-item
            if description.startswith('of which:'):
                sub_items.add(item_num)
            elif description.startswith('Memo item:'):
                memo_items.add(item_num)
            # Check next line for these patterns too
            if i + 1 < len(lines):
                next_line = lines[i + 1].strip()
                if next_line.startswith('of which:'):
                    sub_items.add(item_num)
                if next_line.startswith('Memo item:'):
                    memo_items.add(item_num)

print("Sub-items (of which:):")
for item in sorted(sub_items):
    print(f"  {item}")

print("\nMemo items:")
for item in sorted(memo_items):
    print(f"  {item}")

EOFPYTHON

